detaileddescription.para:
struct_



Struct packing the values 




field_name_



Field name in the struct 




type_



Token type for JSON value corresponding to a primitive type. Must be one of: JSON_TOK_STRING for strings, JSON_TOK_NUMBER for numbers, JSON_TOK_TRUE (or JSON_TOK_FALSE) for booleans.



Here's an example of use: struct foo {
    int32_t some_int;
};

struct json_obj_descr foo[] = {
    JSON_OBJ_DESCR_PRIM(struct foo, some_int, JSON_TOK_NUMBER),
};

struct_



Struct packing the values 




field_name_



Field name in the struct 




sub_descr_



Array of json_obj_descr describing the subobject



Here's an example of use:  struct nested {
     int32_t foo;
     struct {
        int32_t baz;
     } bar;
 };

 struct json_obj_descr nested_bar[] = {
     { ... declare bar.baz descriptor ... },
 };
 struct json_obj_descr nested[] = {
     { ... declare foo descriptor ... },
     JSON_OBJ_DESCR_OBJECT(struct nested, bar, nested_bar),
 };

struct_



Struct packing the values 




field_name_



Field name in the struct 




max_len_



Maximum number of elements in array 




len_field_



Field name in the struct for the number of elements in the array 




elem_type_



Element type, must be a primitive type



Here's an example of use:  struct example {
     int32_t foo[10];
     size_t foo_len;
 };

 struct json_obj_descr array[] = {
      JSON_OBJ_DESCR_ARRAY(struct example, foo, 10, foo_len,
                           JSON_TOK_NUMBER)
 };

struct_



Struct packing the values 




field_name_



Field name in the struct containing the array 




max_len_



Maximum number of elements in the array 




len_field_



Field name in the struct for the number of elements in the array 




elem_descr_



Element descriptor, pointer to a descriptor array 




elem_descr_len_



Number of elements in elem_descr_



Here's an example of use:  struct person_height {
     const char *name;
     int32_t height;
 };

 struct people_heights {
     struct person_height heights[10];
     size_t heights_len;
 };

 struct json_obj_descr person_height_descr[] = {
      JSON_OBJ_DESCR_PRIM(struct person_height, name, JSON_TOK_STRING),
      JSON_OBJ_DESCR_PRIM(struct person_height, height, JSON_TOK_NUMBER),
 };

 struct json_obj_descr array[] = {
      JSON_OBJ_DESCR_OBJ_ARRAY(struct people_heights, heights, 10,
                               heights_len, person_height_descr,
                               ARRAY_SIZE(person_height_descr)),
 };

struct_



Struct packing the values 




field_name_



Field name in the struct containing the array 




max_len_



Maximum number of elements in the array 




len_field_



Field name in the struct for the number of elements in the array 




elem_descr_



Element descriptor, pointer to a descriptor array 




elem_descr_len_



Number of elements in elem_descr_



Here's an example of use:  struct person_height {
     const char *name;
     int32_t height;
 };

 struct person_heights_array {
     struct person_height heights;
 }

 struct people_heights {
     struct person_height_array heights[10];
     size_t heights_len;
 };

 struct json_obj_descr person_height_descr[] = {
     JSON_OBJ_DESCR_PRIM(struct person_height, name, JSON_TOK_STRING),
     JSON_OBJ_DESCR_PRIM(struct person_height, height, JSON_TOK_NUMBER),
 };

 struct json_obj_descr person_height_array_descr[] = {
     JSON_OBJ_DESCR_OBJECT(struct person_heights_array,
                           heights, person_height_descr),
 };

 struct json_obj_descr array_array[] = {
      JSON_OBJ_DESCR_ARRAY_ARRAY(struct people_heights, heights, 10,
                                 heights_len, person_height_array_descr,
                                 ARRAY_SIZE(person_height_array_descr)),
 };

struct_



Struct packing the values 




json_field_name_



String, field name of the array in JSON strings 




struct_field_name_



Field name in the struct containing the array 




max_len_



Maximum number of elements in the array 




len_field_



Field name in the struct for the number of elements in the array 




elem_descr_



Element descriptor, pointer to a descriptor array 




elem_descr_len_



Number of elements in elem_descr_



Here's an example of use:  struct person_height {
     const char *name;
     int32_t height;
 };

 struct people_heights {
     struct person_height heights[10];
     size_t heights_len;
 };

 struct json_obj_descr person_height_descr[] = {
      JSON_OBJ_DESCR_PRIM(struct person_height, name, JSON_TOK_STRING),
      JSON_OBJ_DESCR_PRIM(struct person_height, height, JSON_TOK_NUMBER),
 };

 struct json_obj_descr array[] = {
      JSON_OBJ_DESCR_OBJ_ARRAY_NAMED(struct people_heights,
                                     "people-heights", heights,
                                     10, heights_len,
                                     person_height_descr,
                                     ARRAY_SIZE(person_height_descr)),
 };
